form:Form.form:Scripts:
		function valSancion(me)
{
	if (Ctrl('LIST').RowsCount() == 0)
	{
		me.SetError('No hay niguna sanción seleccionada');
		return false;
	}
	return true;
}

function RELOAD()
{	
	var MyRows;
	var PARAM = "<DATOS oi_personal_emp=\""+Ctrl('oi_personal_emp').GetXValue()+"\" />";		
	MyRows=GetProxy().SQLService().GetXML(Ctrl("main").getResource("QRY_SANCIONES"), PARAM)

	Ctrl("LIST").processResult(MyRows.ToString());	
}
